class Solution {
public:
    string simplifyPath(string path) {
        vector<string> st;
        string token;
        stringstream ss(path);
        while (getline(ss, token, '/')) {
            if (token.empty() || token == ".") continue;
            if (token == "..") { if (!st.empty()) st.pop_back(); }
            else st.push_back(token);
        }
        string res = "";
        for (auto& t : st) res += "/" + t;
        return res.empty() ? "/" : res;
    }
};
